SELECT COUNT(*) FROM hm_query.organisation_flat

    AND id = #{id}
    AND LOWER(company_name) LIKE LOWER(CONCAT('%', #{companyName}, '%'))
    AND active = #{active}
    AND domain = #{domain}
    AND (LOWER(company_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(legal_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR domain LIKE CONCAT('%', #{q}, '%'))

SELECT id, company_name AS "companyName", legal_name AS "legalName", gst_number AS "gstNumber", pan_number AS "panNumber", domain, active, created_at AS "createdAt" FROM hm_query.organisation_flat
AND id = #{id} AND LOWER(company_name) LIKE LOWER(CONCAT('%', #{companyName}, '%')) AND active = #{active} AND domain = #{domain} AND (LOWER(company_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR LOWER(legal_name) LIKE LOWER(CONCAT('%', #{q}, '%')) OR domain LIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
